CREATE OR REPLACE FUNCTION public.create_room_with_password(_name text, _description text, _room_type text, _is_public boolean, _password text DEFAULT NULL, _rules text DEFAULT NULL) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _user_id uuid := auth.uid(); _room_id uuid; _hash text; BEGIN IF _user_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; IF _password IS NOT NULL AND length(_password) > 0 THEN _hash := extensions.crypt(_password, extensions.gen_salt('bf')); END IF; INSERT INTO public.study_rooms (name, description, room_type, owner_id, is_public, password_hash, rules) VALUES (_name, _description, _room_type, _user_id, _is_public, _hash, _rules) RETURNING id INTO _room_id; INSERT INTO public.room_members (room_id, user_id, role) VALUES (_room_id, _user_id, 'owner'); INSERT INTO public.room_activity_log (room_id, user_id, action_type) VALUES (_room_id, _user_id, 'room_created'); RETURN _room_id; END; $$;

CREATE OR REPLACE FUNCTION public.create_room_with_password(_name text, _description text, _room_type text, _is_public boolean, _password text DEFAULT NULL, _rules text DEFAULT NULL, _country text DEFAULT NULL) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _user_id uuid := auth.uid(); _room_id uuid; _hash text; BEGIN IF _user_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; IF _password IS NOT NULL AND length(_password) > 0 THEN _hash := extensions.crypt(_password, extensions.gen_salt('bf')); END IF; INSERT INTO public.study_rooms (name, description, room_type, owner_id, is_public, password_hash, rules, country) VALUES (_name, _description, _room_type, _user_id, _is_public, _hash, _rules, _country) RETURNING id INTO _room_id; INSERT INTO public.room_members (room_id, user_id, role) VALUES (_room_id, _user_id, 'owner'); INSERT INTO public.room_activity_log (room_id, user_id, action_type) VALUES (_room_id, _user_id, 'room_created'); RETURN _room_id; END; $$;

CREATE OR REPLACE FUNCTION public.update_room_password(_room_id uuid, _password text DEFAULT NULL) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _caller_id uuid := auth.uid(); BEGIN IF _caller_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; IF NOT is_room_owner(_caller_id, _room_id) THEN RAISE EXCEPTION 'Only the room owner can change the password'; END IF; IF _password IS NOT NULL AND length(_password) > 0 THEN UPDATE public.study_rooms SET password_hash = extensions.crypt(_password, extensions.gen_salt('bf')), is_public = false WHERE id = _room_id; ELSE UPDATE public.study_rooms SET password_hash = NULL WHERE id = _room_id; END IF; END; $$;

CREATE OR REPLACE FUNCTION public.join_public_room(_room_id uuid, _password text DEFAULT NULL) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _user_id uuid := auth.uid(); _room record; _already_member boolean; BEGIN IF _user_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; SELECT * INTO _room FROM public.study_rooms WHERE id = _room_id AND is_active = true; IF _room IS NULL THEN RAISE EXCEPTION 'Room not found'; END IF; IF _room.password_hash IS NOT NULL THEN IF _password IS NULL OR extensions.crypt(_password, _room.password_hash) != _room.password_hash THEN RAISE EXCEPTION 'Invalid password'; END IF; END IF; SELECT EXISTS(SELECT 1 FROM public.room_members WHERE room_id = _room_id AND user_id = _user_id) INTO _already_member; IF _already_member THEN RAISE EXCEPTION 'Already a member'; END IF; INSERT INTO public.room_members (room_id, user_id, role) VALUES (_room_id, _user_id, 'member'); INSERT INTO public.room_activity_log (room_id, user_id, action_type) VALUES (_room_id, _user_id, 'member_joined'); RETURN _room_id; END; $$;

CREATE OR REPLACE FUNCTION public.join_room_by_invite_code(_code text, _password text DEFAULT NULL) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _room_id uuid; _password_hash text; _user_id uuid := auth.uid(); _already_member boolean; BEGIN IF _user_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; SELECT id, password_hash INTO _room_id, _password_hash FROM public.study_rooms WHERE invite_code = upper(_code) AND is_active = true; IF _room_id IS NULL THEN RAISE EXCEPTION 'Invalid invite code'; END IF; IF _password_hash IS NOT NULL THEN IF _password IS NULL OR extensions.crypt(_password, _password_hash) != _password_hash THEN RAISE EXCEPTION 'Invalid password'; END IF; END IF; SELECT EXISTS(SELECT 1 FROM public.room_members WHERE room_id = _room_id AND user_id = _user_id) INTO _already_member; IF _already_member THEN RAISE EXCEPTION 'Already a member'; END IF; INSERT INTO public.room_members (room_id, user_id, role) VALUES (_room_id, _user_id, 'member'); INSERT INTO public.room_activity_log (room_id, user_id, action_type) VALUES (_room_id, _user_id, 'member_joined'); RETURN _room_id; END; $$;